25	func (h *BookingHandler) BookingPage(c *gin.Context) {
26		user := GetCurrentUser(c)
27		bookings, _ := h.BookingSvc.GetBookings(user.ID)
28		venues, _ := h.BookingSvc.GetVenues()
29	
30		// Get only referenced user names (not the entire user table)
31		userIDs := make(map[uint]bool)
32		for _, b := range bookings {
33			userIDs[b.RequesterID] = true
34			if b.PartnerID != nil {
35				userIDs[*b.PartnerID] = true
36			}
37		}
38		userMap := make(map[uint]string)
39		if len(userIDs) > 0 {
40			ids := make([]uint, 0, len(userIDs))
41			for id := range userIDs {
42				ids = append(ids, id)
43			}
44			var users []models.User
45			h.DB.Where("id IN ?", ids).Find(&users)
46			for _, u := range users {
47				userMap[u.ID] = u.FullName
48			}
49		}
50	
51		// Fetch distinct training styles from DB for the filter dropdown
52		var styles []string
53		h.DB.Model(&models.TrainerProfile{}).Distinct("primary_style").Where("primary_style != ''").Pluck("primary_style", &styles)
54	
55		c.HTML(http.StatusOK, "bookings.html", gin.H{
56			"title":    "Training Sessions",
57			"user":     user,
58			"bookings": bookings,
59			"venues":   venues,
60			"userMap":  userMap,
61			"styles":   styles,
62		})
63	}
