65	func (h *BookingHandler) GetSlots(c *gin.Context) {
66		venueID, _ := strconv.ParseUint(c.Query("venue_id"), 10, 64)
67		dateStr := c.Query("date")
68	
69		date, err := time.Parse("2006-01-02", dateStr)
70		if err != nil {
71			c.JSON(http.StatusBadRequest, gin.H{"error": "invalid date format"})
72			return
73		}
74	
75		// Return all slots with availability status — frontend renders entirely from this
76		orgID, _ := c.Get("orgID")
77		allSlots := h.BookingSvc.GetAllSlots(uint(venueID), date, orgID.(uint))
78		c.JSON(http.StatusOK, gin.H{"slots": allSlots})
79	}
