81	func (h *BookingHandler) MatchPartners(c *gin.Context) {
82		user := GetCurrentUser(c)
83		skillRange, _ := strconv.Atoi(c.DefaultQuery("skill_range", "2"))
84		weightRange, _ := strconv.ParseFloat(c.DefaultQuery("weight_range", "20"), 64)
85		style := c.Query("style")
86	
87		orgID, _ := c.Get("orgID")
88		matches, err := h.BookingSvc.MatchPartners(user.ID, skillRange, weightRange, style, orgID.(uint))
89		if err != nil {
90			c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
91			return
92		}
93	
94		// Enrich with user names
95		type PartnerMatch struct {
96			models.TrainerProfile
97			FullName string `json:"full_name"`
98		}
99		var enriched []PartnerMatch
100		for _, m := range matches {
101			var u models.User
102			h.DB.First(&u, m.UserID)
103			enriched = append(enriched, PartnerMatch{TrainerProfile: m, FullName: u.FullName})
104		}
105	
106		c.JSON(http.StatusOK, gin.H{"matches": enriched})
107	}
