109	func (h *BookingHandler) CheckConflicts(c *gin.Context) {
110		user := GetCurrentUser(c)
111		venueID, _ := strconv.ParseUint(c.Query("venue_id"), 10, 64)
112		slotStr := c.Query("slot_start")
113	
114		slotStart, err := time.Parse(time.RFC3339, slotStr)
115		if err != nil {
116			c.JSON(http.StatusBadRequest, gin.H{"error": "invalid slot time"})
117			return
118		}
119	
120		var partnerID *uint
121		if pid := c.Query("partner_id"); pid != "" {
122			id, _ := strconv.ParseUint(pid, 10, 64)
123			uid := uint(id)
124			partnerID = &uid
125		}
126	
127		orgID, _ := c.Get("orgID")
128		conflicts, err := h.BookingSvc.CheckConflicts(user.ID, partnerID, uint(venueID), slotStart, orgID.(uint))
129		if err != nil {
130			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
131			return
132		}
133	
134		c.JSON(http.StatusOK, gin.H{"conflicts": conflicts})
135	}
