137	func (h *BookingHandler) CreateBooking(c *gin.Context) {
138		user := GetCurrentUser(c)
139		venueID, err := strconv.ParseUint(c.PostForm("venue_id"), 10, 64)
140		if err != nil || venueID == 0 {
141			c.HTML(http.StatusBadRequest, "error.html", gin.H{"error": "invalid venue ID"})
142			return
143		}
144		slotStr := c.PostForm("slot_start")
145	
146		slotStart, err := time.Parse(time.RFC3339, slotStr)
147		if err != nil {
148			slotStart, err = time.Parse("2006-01-02T15:04", slotStr)
149			if err != nil {
150				c.HTML(http.StatusBadRequest, "error.html", gin.H{"error": "invalid slot time"})
151				return
152			}
153		}
154	
155		var partnerID *uint
156		if pid := c.PostForm("partner_id"); pid != "" {
157			id, _ := strconv.ParseUint(pid, 10, 64)
158			uid := uint(id)
159			partnerID = &uid
160		}
161	
162		orgID, _ := c.Get("orgID")
163		_, err = h.BookingSvc.CreateBooking(user.ID, partnerID, uint(venueID), slotStart, user.ID, orgID.(uint))
164		if err != nil {
165			c.HTML(http.StatusBadRequest, "error.html", gin.H{"error": err.Error()})
166			return
167		}
168	
169		c.Redirect(http.StatusFound, "/bookings")
170	}
