172	func (h *BookingHandler) TransitionBooking(c *gin.Context) {
173		user := GetCurrentUser(c)
174		bookingID, err := strconv.ParseUint(c.Param("id"), 10, 64)
175		if err != nil {
176			c.JSON(http.StatusBadRequest, gin.H{"error": "invalid booking ID"})
177			return
178		}
179		newStatus := models.BookingStatus(c.PostForm("status"))
180		note := strings.TrimSpace(c.PostForm("note"))
181		if note == "" {
182			c.JSON(http.StatusBadRequest, gin.H{"error": "a reason/note is required for booking status changes"})
183			return
184		}
185	
186		// Authorization: booking must belong to user's org, and user must own it or be staff/admin
187		var booking models.Booking
188		if err := h.DB.First(&booking, uint(bookingID)).Error; err != nil {
189			c.JSON(http.StatusNotFound, gin.H{"error": "booking not found"})
190			return
191		}
192		orgID, _ := c.Get("orgID")
193		if booking.OrganizationID != orgID.(uint) {
194			c.JSON(http.StatusForbidden, gin.H{"error": "access denied"})
195			return
196		}
197		if user.Role != models.RoleAdmin && user.Role != models.RoleStaff {
198			if booking.RequesterID != user.ID && (booking.PartnerID == nil || *booking.PartnerID != user.ID) {
199				c.JSON(http.StatusForbidden, gin.H{"error": "you can only modify your own bookings"})
200				return
201			}
202		}
203	
204		if err := h.BookingSvc.TransitionBooking(uint(bookingID), newStatus, user.ID, note); err != nil {
205			c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
206			return
207		}
208	
209		c.Redirect(http.StatusFound, "/bookings")
210	}
