25	var timeFormatRE = regexp.MustCompile(`^\d{2}:\d{2}$`)
26	
27	// verifyMenuItemOrg checks that a menu item belongs to the user's org. Returns false and sends 403 if not.
28	func (h *MenuHandler) verifyMenuItemOrg(c *gin.Context, itemID uint) bool {
29		item, err := h.MenuSvc.GetMenuItem(itemID)
30		if err != nil {
31			c.JSON(http.StatusNotFound, gin.H{"error": "item not found"})
32			return false
33		}
34		orgID, _ := c.Get("orgID")
35		if item.OrganizationID != orgID.(uint) {
36			c.JSON(http.StatusForbidden, gin.H{"error": "access denied: item belongs to another organization"})
37			return false
38		}
39		return true
40	}
