42	func (h *MenuHandler) MenuPage(c *gin.Context) {
43		user := GetCurrentUser(c)
44		orgID, _ := c.Get("orgID")
45		categories, _ := h.MenuSvc.GetCategories(orgID.(uint))
46	
47		var catID *uint
48		if cid := c.Query("category_id"); cid != "" {
49			if id, err := strconv.ParseUint(cid, 10, 64); err == nil {
50				uid := uint(id)
51				catID = &uid
52			}
53		}
54	
55		items, _ := h.MenuSvc.GetMenuItems(orgID.(uint), catID)
56	
57		type EnrichedItem struct {
58			models.MenuItem
59			Available   bool                    `json:"available"`
60			FinalPrice  float64                 `json:"final_price"`
61			Substitutes []models.MenuItem       `json:"substitutes"`
62			Choices     []models.MenuItemChoice `json:"choices"`
63		}
64	
65		var enriched []EnrichedItem
66		for _, item := range items {
67			avail, _ := h.MenuSvc.IsWithinSellWindow(item.ID, time.Now())
68			price, _ := h.MenuSvc.CalculatePrice(item.ID, "dine_in", false)
69			subs, _ := h.MenuSvc.GetSubstitutes(item.ID)
70			choices, _ := h.MenuSvc.GetChoices(item.ID)
71			enriched = append(enriched, EnrichedItem{
72				MenuItem:    item,
73				Available:   avail && !item.SoldOut,
74				FinalPrice:  price,
75				Substitutes: subs,
76				Choices:     choices,
77			})
78		}
79	
80		c.HTML(http.StatusOK, "menu.html", gin.H{
81			"title":      "Dining Menu",
82			"user":       user,
83			"categories": categories,
84			"items":      enriched,
85			"activeCat":  catID,
86		})
87	}
