105	func (h *MenuHandler) CreateCategory(c *gin.Context) {
106		name := strings.TrimSpace(c.PostForm("name"))
107		if name == "" {
108			c.JSON(http.StatusBadRequest, gin.H{"error": "category name is required"})
109			return
110		}
111	
112		orgID, _ := c.Get("orgID")
113		var parentID *uint
114		if pid := c.PostForm("parent_id"); pid != "" {
115			if id, err := strconv.ParseUint(pid, 10, 64); err == nil {
116				// Verify parent category belongs to same org
117				var parentCat models.MenuCategory
118				if err := h.MenuSvc.DB.First(&parentCat, uint(id)).Error; err != nil || parentCat.OrganizationID != orgID.(uint) {
119					c.JSON(http.StatusForbidden, gin.H{"error": "parent category not in your organization"})
120					return
121				}
122				uid := uint(id)
123				parentID = &uid
124			}
125		}
126		sortOrder, _ := strconv.Atoi(c.PostForm("sort_order"))
127	
128		user := GetCurrentUser(c)
129		cat := &models.MenuCategory{OrganizationID: orgID.(uint), Name: name, ParentID: parentID, SortOrder: sortOrder}
130		if err := h.MenuSvc.CreateCategory(cat, user.ID); err != nil {
131			c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to create category: " + err.Error()})
132			return
133		}
134		c.Redirect(http.StatusFound, "/menu/manage")
135	}
