137	func (h *MenuHandler) CreateMenuItem(c *gin.Context) {
138		user := GetCurrentUser(c)
139		catID, err := strconv.ParseUint(c.PostForm("category_id"), 10, 64)
140		if err != nil || catID == 0 {
141			c.JSON(http.StatusBadRequest, gin.H{"error": "invalid category ID"})
142			return
143		}
144		// Verify category belongs to caller's org
145		orgIDv, _ := c.Get("orgID")
146		var cat models.MenuCategory
147		if err := h.MenuSvc.DB.First(&cat, uint(catID)).Error; err != nil || cat.OrganizationID != orgIDv.(uint) {
148			c.JSON(http.StatusForbidden, gin.H{"error": "category not in your organization"})
149			return
150		}
151	
152		sku := strings.TrimSpace(c.PostForm("sku"))
153		name := strings.TrimSpace(c.PostForm("name"))
154		if sku == "" || name == "" {
155			c.JSON(http.StatusBadRequest, gin.H{"error": "SKU and name are required"})
156			return
157		}
158	
159		priceDineIn, _ := strconv.ParseFloat(c.PostForm("base_price_dine_in"), 64)
160		priceTakeout, _ := strconv.ParseFloat(c.PostForm("base_price_takeout"), 64)
161		memberDiscount, _ := strconv.ParseFloat(c.PostForm("member_discount"), 64)
162	
163		if priceDineIn < 0 || priceTakeout < 0 {
164			c.JSON(http.StatusBadRequest, gin.H{"error": "prices must be >= 0"})
165			return
166		}
167		if memberDiscount < 0 || memberDiscount > 100 {
168			c.JSON(http.StatusBadRequest, gin.H{"error": "member discount must be between 0 and 100"})
169			return
170		}
171	
172		itemType := c.PostForm("item_type")
173		validTypes := map[string]bool{"dish": true, "combo": true, "addon": true}
174		if !validTypes[itemType] {
175			c.JSON(http.StatusBadRequest, gin.H{"error": "item type must be dish, combo, or addon"})
176			return
177		}
178	
179		orgID, _ := c.Get("orgID")
180		item := &models.MenuItem{
181			OrganizationID:  orgID.(uint),
182			CategoryID:       uint(catID),
183			SKU:              sku,
184			Name:             name,
185			Description:      c.PostForm("description"),
186			ItemType:         itemType,
187			BasePriceDineIn:  priceDineIn,
188			BasePriceTakeout: priceTakeout,
189			MemberDiscount:   memberDiscount,
190		}
191	
192		if err := h.MenuSvc.CreateMenuItem(item, user.ID); err != nil {
193			c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to create item: " + err.Error()})
194			return
195		}
196		c.Redirect(http.StatusFound, "/menu/manage")
197	}
