217	func (h *MenuHandler) SetSellWindows(c *gin.Context) {
218		id, err := strconv.ParseUint(c.Param("id"), 10, 64)
219		if err != nil {
220			c.JSON(http.StatusBadRequest, gin.H{"error": "invalid item ID"})
221			return
222		}
223		if !h.verifyMenuItemOrg(c, uint(id)) {
224			return
225		}
226	
227		days := c.PostFormArray("day_of_week")
228		opens := c.PostFormArray("open_time")
229		closes := c.PostFormArray("close_time")
230	
231		var windows []models.SellWindow
232		for i := range days {
233			if i >= len(opens) || i >= len(closes) {
234				break
235			}
236			day, dayErr := strconv.Atoi(days[i])
237			if dayErr != nil || day < 0 || day > 6 {
238				c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("invalid day_of_week at index %d: must be 0-6", i)})
239				return
240			}
241			if !timeFormatRE.MatchString(opens[i]) || !timeFormatRE.MatchString(closes[i]) {
242				c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("invalid time format at index %d: use HH:MM", i)})
243				return
244			}
245			if opens[i] >= closes[i] {
246				c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("open time must be before close time at index %d", i)})
247				return
248			}
249			windows = append(windows, models.SellWindow{
250				DayOfWeek: day, OpenTime: opens[i], CloseTime: closes[i],
251			})
252		}
253	
254		user := GetCurrentUser(c)
255		if err := h.MenuSvc.SetSellWindows(uint(id), windows, user.ID); err != nil {
256			c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to set sell windows: " + err.Error()})
257			return
258		}
259		c.Redirect(http.StatusFound, "/menu/manage")
260	}
