262	func (h *MenuHandler) SetSubstitutes(c *gin.Context) {
263		id, err := strconv.ParseUint(c.Param("id"), 10, 64)
264		if err != nil {
265			c.JSON(http.StatusBadRequest, gin.H{"error": "invalid item ID"})
266			return
267		}
268		if !h.verifyMenuItemOrg(c, uint(id)) {
269			return
270		}
271		subIDs := c.PostForm("substitute_ids")
272		orgID, _ := c.Get("orgID")
273	
274		var ids []uint
275		for _, s := range strings.Split(subIDs, ",") {
276			s = strings.TrimSpace(s)
277			if s == "" {
278				continue
279			}
280			if sid, err := strconv.ParseUint(s, 10, 64); err == nil {
281				// Verify each substitute item belongs to same org
282				subItem, subErr := h.MenuSvc.GetMenuItem(uint(sid))
283				if subErr != nil || subItem.OrganizationID != orgID.(uint) {
284					c.JSON(http.StatusForbidden, gin.H{"error": fmt.Sprintf("substitute item %d not in your organization", sid)})
285					return
286				}
287				ids = append(ids, uint(sid))
288			}
289		}
290	
291		user := GetCurrentUser(c)
292		if err := h.MenuSvc.SetSubstitutes(uint(id), ids, user.ID); err != nil {
293			c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to set substitutes: " + err.Error()})
294			return
295		}
296		c.Redirect(http.StatusFound, "/menu/manage")
297	}
