400	func (h *MenuHandler) CreateOrder(c *gin.Context) {
401		user := GetCurrentUser(c)
402		orderType := c.PostForm("order_type")
403		isMember := c.PostForm("is_member") == "true"
404	
405		itemIDs := c.PostFormArray("item_id")
406		quantities := c.PostFormArray("quantity")
407	
408		if len(itemIDs) == 0 {
409			c.HTML(http.StatusBadRequest, "error.html", gin.H{"error": "no items in order"})
410			return
411		}
412	
413		var orderItems []models.MenuOrderItem
414		var totalPrice float64
415	
416		orgID, _ := c.Get("orgID")
417		for i, idStr := range itemIDs {
418			itemID, err := strconv.ParseUint(idStr, 10, 64)
419			if err != nil {
420				c.HTML(http.StatusBadRequest, "error.html", gin.H{"error": fmt.Sprintf("invalid item ID at position %d", i)})
421				return
422			}
423			// Verify every ordered item belongs to the caller's org
424			item, itemErr := h.MenuSvc.GetMenuItem(uint(itemID))
425			if itemErr != nil || item.OrganizationID != orgID.(uint) {
426				c.HTML(http.StatusForbidden, "error.html", gin.H{"error": fmt.Sprintf("item %d not available in your organization", itemID)})
427				return
428			}
429			qty := 1
430			if i < len(quantities) {
431				qty, _ = strconv.Atoi(quantities[i])
432				if qty < 1 {
433					qty = 1
434				}
435			}
436	
437			price, err := h.MenuSvc.CalculatePrice(uint(itemID), orderType, isMember)
438			if err != nil {
439				c.HTML(http.StatusBadRequest, "error.html", gin.H{"error": fmt.Sprintf("cannot price item %d: %s", itemID, err.Error())})
440				return
441			}
442	
443			orderItems = append(orderItems, models.MenuOrderItem{
444				MenuItemID: uint(itemID), Quantity: qty, UnitPrice: price,
445			})
446			totalPrice += price * float64(qty)
447		}
448	
449		if len(orderItems) == 0 {
450			c.HTML(http.StatusBadRequest, "error.html", gin.H{"error": "order has no valid items"})
451			return
452		}
453	
454		order := &models.MenuOrder{
455			OrganizationID: orgID.(uint),
456			UserID: user.ID, OrderType: orderType,
457			TotalPrice: totalPrice, IsMember: isMember, Status: "pending",
458		}
459	
460		if err := h.MenuSvc.CreateOrder(order, orderItems); err != nil {
461			c.HTML(http.StatusBadRequest, "error.html", gin.H{"error": err.Error()})
462			return
463		}
464	
465		c.Redirect(http.StatusFound, "/menu")
466	}
