38	func (h *AuthHandler) Login(c *gin.Context) {
39		// Validate CSRF token on login POST
40		cookieToken, _ := c.Cookie("login_csrf")
41		formToken := c.PostForm("csrf_token")
42		if cookieToken == "" || formToken == "" || cookieToken != formToken {
43			views.Render(c, http.StatusOK, views.LoginPage("Invalid request. Please try again.", ensureLoginCSRF(c)))
44			return
45		}
46	
47		username := c.PostForm("username")
48		password := c.PostForm("password")
49	
50		user, sessionID, err := h.AuthSvc.Login(username, password)
51		if err != nil {
52			views.Render(c, http.StatusOK, views.LoginPage("Invalid username or password", ensureLoginCSRF(c)))
53			return
54		}
55	
56		c.SetSameSite(http.SameSiteLaxMode)
57		c.SetCookie("session_id", sessionID, 86400, "/", "", h.Cfg.SecureCookies, true)
58		_ = user
59		c.Redirect(http.StatusFound, "/dashboard")
60	}
