66	
67		tok, tokenStr, err := h.AuthSvc.IssueAPIToken(user.ID, description, 24*time.Hour)
68		if err != nil {
69			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
70			return
71		}
72		c.JSON(http.StatusOK, gin.H{
73			"token":       tokenStr,
74			"hmac_secret": h.Cfg.HMACSecret,
75			"expires_at":  tok.ExpiresAt.Format("01/02/2006 03:04 PM"),
76			"message":     "Store this token securely — it cannot be retrieved again.",
77		})
78	}
