206	func (h *AuthHandler) Register(c *gin.Context) {
207		username := c.PostForm("username")
208		password := c.PostForm("password")
209		passwordConfirm := c.PostForm("password_confirm")
210		fullName := c.PostForm("full_name")
211		email := c.PostForm("email")
212		role := models.Role(c.PostForm("role"))
213	
214		// Password validation
215		if len(password) < 8 {
216			c.HTML(http.StatusOK, "register.html", gin.H{
217				"title": "Register New User", "error": "Password must be at least 8 characters", "user": GetCurrentUser(c),
218			})
219			return
220		}
221		if password != passwordConfirm {
222			c.HTML(http.StatusOK, "register.html", gin.H{
223				"title": "Register New User", "error": "Passwords do not match", "user": GetCurrentUser(c),
224			})
225			return
226		}
227	
228		var deptID *uint
229		currentUser := GetCurrentUser(c)
230		if d, err := strconv.ParseUint(c.PostForm("department_id"), 10, 64); err == nil {
231			did := uint(d)
232			// Validate department belongs to the admin's organization
233			var dept models.DepartmentRecord
234			if err := h.DB.First(&dept, did).Error; err != nil || dept.OrganizationID != currentUser.OrganizationID {
235				c.HTML(http.StatusOK, "register.html", gin.H{
236					"title": "Register New User", "error": "Department does not belong to your organization", "user": currentUser,
237				})
238				return
239			}
240			deptID = &did
241		}
242	
243		// Derive org from the admin creating the user — not hardcoded
244		newUser, err := h.AuthSvc.Register(username, password, fullName, email, role, currentUser.OrganizationID, deptID)
245		if err != nil {
246			c.HTML(http.StatusOK, "register.html", gin.H{
247				"title": "Register New User",
248				"error": err.Error(),
249				"user":  GetCurrentUser(c),
250			})
251			return
252		}
253	
254		h.AuditSvc.LogChange("users", newUser.ID, "user_created", currentUser.ID,
255			fmt.Sprintf("User %s created with role %s", username, role), newUser)
256		c.Redirect(http.StatusFound, "/admin/users")
257	}
