284	func ensureLoginCSRF(c *gin.Context) string {
285		if token, _ := c.Cookie("login_csrf"); token != "" {
286			return token
287		}
288		b := make([]byte, 32)
289		rand.Read(b)
290		token := hex.EncodeToString(b)
291		c.SetSameSite(http.SameSiteLaxMode)
292		c.SetCookie("login_csrf", token, 600, "/", "", false, true)
293		return token
294	}
