39	
40		// For students/faculty, show their own records
41		// For clinicians/admins, show department view
42		targetUserID := user.ID
43		if qID := c.Query("user_id"); qID != "" {
44			if id, err := strconv.ParseUint(qID, 10, 64); err == nil {
45				if h.enforceScopeForHealth(c, uint(id)) {
