53		encounters, encErr := h.HealthSvc.GetEncounters(targetUserID)
54		attachments, attErr := h.HealthSvc.GetAttachments(targetUserID)
55	
56		var serviceErrors []string
57		if recErr != nil && recErr.Error() != "record not found" {
