60		if vitErr != nil {
61			serviceErrors = append(serviceErrors, "Failed to load vitals")
62		}
63		if encErr != nil {
64			serviceErrors = append(serviceErrors, "Failed to load encounters")
65		}
66		if attErr != nil {
67			serviceErrors = append(serviceErrors, "Failed to load attachments")
68		}
69	
70		maskedSSN := services.MaskSSN(user.SSN, user.Role)
71	
72		// Build Templ dashboard data
73		dd := views.DashboardData{
74			User:          &views.UserInfo{FullName: user.FullName, Role: string(user.Role)},
