76			TargetUser:    targetUserID,
77			ServiceErrors: serviceErrors,
78			IsEditor:      user.Role == models.RoleClinician || user.Role == models.RoleAdmin,
79		}
80		if record != nil {
81			dd.HasRecord = true
82			dd.BloodType = record.BloodType
83			dd.Allergies = record.Allergies
84			dd.Conditions = record.Conditions
85			dd.Medications = record.Medications
86		}
87		for _, v := range vitals {
88			dd.Vitals = append(dd.Vitals, views.VitalRow{
