94			})
95		}
96		for _, e := range encounters {
97			dd.Encounters = append(dd.Encounters, views.EncounterRow{
98				Date:       e.EncounterDate.Format("01/02/2006 03:04 PM"),
99				Department: string(e.Department),
100				Complaint:  e.ChiefComplaint,
101				Diagnosis:  e.Diagnosis,
102				Treatment:  e.Treatment,
103				ID:         e.ID,
104			})
105		}
106		for _, a := range attachments {
107			dd.Attachments = append(dd.Attachments, views.AttachmentRow{
108				ID:       a.ID,
