118	func (h *HealthHandler) UpdateHealthRecord(c *gin.Context) {
119		user := GetCurrentUser(c)
120		targetUserID := user.ID
121		if id, err := strconv.ParseUint(c.PostForm("user_id"), 10, 64); err == nil {
122			if !h.enforceScopeForHealth(c, uint(id)) {
123				c.JSON(http.StatusForbidden, gin.H{"error": "access denied: cannot modify this record"})
124				return
125			}
126			targetUserID = uint(id)
127		}
128	
129		// Validate text field lengths (max 10KB each)
130		const maxTextLen = 10240
131		for _, field := range []string{"allergies", "conditions", "medications", "reason"} {
132			if len(c.PostForm(field)) > maxTextLen {
133				c.JSON(http.StatusBadRequest, gin.H{"error": field + " exceeds maximum length (10KB)"})
134				return
135			}
136		}
137	
138		// Require non-empty reason for audit trail (prompt: "human-readable reason")
139		reason := strings.TrimSpace(c.PostForm("reason"))
140		if reason == "" {
141			c.JSON(http.StatusBadRequest, gin.H{"error": "reason is required for health record changes"})
142			return
143		}
144	
145		_, err := h.HealthSvc.UpsertHealthRecord(
146			targetUserID,
147			user.ID,
148			c.PostForm("allergies"),
149			c.PostForm("conditions"),
150			c.PostForm("medications"),
151			c.PostForm("blood_type"),
152			reason,
153		)
154	
155		if err != nil {
156			c.HTML(http.StatusInternalServerError, "error.html", gin.H{"error": err.Error()})
157			return
158		}
159	
160		c.Redirect(http.StatusFound, "/dashboard")
161	}
