229	func (h *HealthHandler) UploadAttachment(c *gin.Context) {
230		user := GetCurrentUser(c)
231		targetUserID := user.ID
232	
233		// Students/faculty can ONLY upload to their own record.
234		// Staff cannot upload at all (not a health role).
235		// Clinicians/admins can upload within their department/org scope.
236		if user.Role == models.RoleStaff {
237			c.JSON(http.StatusForbidden, gin.H{"error": "staff cannot upload health documents"})
238			return
239		}
240	
241		if id, err := strconv.ParseUint(c.PostForm("user_id"), 10, 64); err == nil {
242			if user.Role == models.RoleStudent || user.Role == models.RoleFaculty {
243				// Students/faculty: self-only, reject any other target
244				if uint(id) != user.ID {
245					c.JSON(http.StatusForbidden, gin.H{"error": "you can only upload documents to your own record"})
246					return
247				}
248			} else {
249				// Clinician/admin: enforce department/org scope
250				if !h.enforceScopeForHealth(c, uint(id)) {
251					c.JSON(http.StatusForbidden, gin.H{"error": "access denied: cannot upload to another user's record"})
252					return
253				}
254			}
255			targetUserID = uint(id)
256		}
257	
258		file, err := c.FormFile("file")
259		if err != nil {
260			c.JSON(http.StatusBadRequest, gin.H{"error": "no file provided"})
261			return
262		}
263	
264		// Server-side validation (client-side also validates)
265		if file.Size > 10*1024*1024 {
266			c.JSON(http.StatusBadRequest, gin.H{"error": "file exceeds 10MB limit"})
267			return
268		}
269	
270		src, err := file.Open()
271		if err != nil {
272			c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to read file"})
273			return
274		}
275		defer src.Close()
276	
277		// Read first 512 bytes for magic byte detection
278		header := make([]byte, 512)
279		n, _ := src.Read(header)
280		detectedType := http.DetectContentType(header[:n])
281	
282		// Reset reader to beginning
283		src.Close()
284		src, err = file.Open()
285		if err != nil {
286			c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to read file"})
287			return
288		}
289		defer src.Close()
290	
291		allowed := map[string]bool{
292			"application/pdf": true,
293			"image/jpeg":      true,
294			"image/png":       true,
295			"image/gif":       true,
296		}
297		// STRICT file type validation: both declared AND detected types must be in the allowlist.
298		// application/octet-stream is NOT accepted — the file must be positively identified.
299		declaredType := file.Header.Get("Content-Type")
300		if !allowed[declaredType] {
301			c.JSON(http.StatusBadRequest, gin.H{"error": "file type not allowed. Only PDF, JPEG, PNG, GIF accepted"})
302			return
303		}
304		if !allowed[detectedType] {
305			c.JSON(http.StatusBadRequest, gin.H{"error": "file content does not match allowed types (detected: " + detectedType + ")"})
306			return
307		}
308	
309		attachment, err := h.HealthSvc.SaveAttachment(file, src, targetUserID, user.ID)
310		if err != nil {
311			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
312			return
313		}
314	
315		c.JSON(http.StatusOK, gin.H{
316			"message":    "File uploaded successfully",
317			"attachment": attachment,
318		})
319	}
