321	func (h *HealthHandler) DownloadAttachment(c *gin.Context) {
322		user := GetCurrentUser(c)
323		attachmentID, _ := strconv.ParseUint(c.Param("id"), 10, 64)
324	
325		var attachment models.Attachment
326		if err := h.HealthSvc.DB.First(&attachment, uint(attachmentID)).Error; err != nil {
327			c.JSON(http.StatusNotFound, gin.H{"error": "attachment not found"})
328			return
329		}
330	
331		// Verify the user has access to this attachment
332		if !h.enforceScopeForHealth(c, attachment.UserID) {
333			c.JSON(http.StatusForbidden, gin.H{"error": "access denied"})
334			return
335		}
336		_ = user
337	
338		// Sanitize filename to prevent header injection
339		safeName := strings.Map(func(r rune) rune {
340			if r == '"' || r == '\\' || r == '\n' || r == '\r' || r == '/' {
341				return '_'
342			}
343			return r
344		}, attachment.FileName)
345		c.Header("Content-Disposition", "attachment; filename=\""+safeName+"\"")
346		c.Header("Content-Type", attachment.ContentType)
347		c.File(attachment.FilePath)
348	}
