427	func (h *HealthHandler) RecordHistory(c *gin.Context) {
428		user := GetCurrentUser(c)
429		table := c.Query("table")
430		recordID, _ := strconv.ParseUint(c.Query("record_id"), 10, 64)
431	
432		// Allowlist of tables non-admin users can query
433		allowedTables := map[string]bool{
434			"health_records": true,
435			"vitals":         true,
436			"encounters":     true,
437		}
438	
439		// ALL non-admin users are restricted to the allowlist. Staff included.
440		if user.Role != models.RoleAdmin {
441			if !allowedTables[table] {
442				c.JSON(http.StatusForbidden, gin.H{"error": "access denied: table not permitted"})
443				return
444			}
445		}
446	
447		// Object-level authorization: verify the record belongs to the user or is within their scope
448		switch table {
449		case "health_records":
450			var rec models.HealthRecord
451			if err := h.HealthSvc.DB.First(&rec, recordID).Error; err != nil {
452				c.JSON(http.StatusForbidden, gin.H{"error": "record not found"})
453				return
454			}
455			if !h.enforceScopeForHealth(c, rec.UserID) {
456				c.JSON(http.StatusForbidden, gin.H{"error": "access denied"})
457				return
458			}
459		case "encounters":
460			var enc models.Encounter
461			if err := h.HealthSvc.DB.First(&enc, recordID).Error; err != nil {
462				c.JSON(http.StatusForbidden, gin.H{"error": "record not found"})
463				return
464			}
465			if !h.enforceScopeForHealth(c, enc.UserID) {
466				c.JSON(http.StatusForbidden, gin.H{"error": "access denied"})
467				return
468			}
469		case "vitals":
470			var v models.Vital
471			if err := h.HealthSvc.DB.First(&v, recordID).Error; err != nil {
472				c.JSON(http.StatusForbidden, gin.H{"error": "record not found"})
473				return
474			}
475			if !h.enforceScopeForHealth(c, v.UserID) {
476				c.JSON(http.StatusForbidden, gin.H{"error": "access denied"})
477				return
478			}
479		}
480	
481		logs, err := h.AuditSvc.GetHistory(table, uint(recordID))
482		if err != nil {
483			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
484			return
485		}
486	
487		c.JSON(http.StatusOK, logs)
488	}
