25	// ===================== CSV WATCHER =====================
26	
27	type CSVWatcher struct {
28		DB       *gorm.DB
29		WatchDir string
30		done     chan struct{}
31	}
32	
33	func NewCSVWatcher(db *gorm.DB, watchDir string) *CSVWatcher {
34		return &CSVWatcher{DB: db, WatchDir: watchDir, done: make(chan struct{})}
35	}
36	
37	func (w *CSVWatcher) Start() {
38		go func() {
39			ticker := time.NewTicker(10 * time.Second)
40			defer ticker.Stop()
41	
42			for {
43				select {
44				case <-ticker.C:
45					w.processFiles()
46				case <-w.done:
47					return
48				}
49			}
50		}()
51		log.Printf("CSV Watcher started on directory: %s", w.WatchDir)
52	}
53	
54	func (w *CSVWatcher) Stop() {
55		close(w.done)
56	}
57	
58	func (w *CSVWatcher) processFiles() {
59		if err := os.MkdirAll(w.WatchDir, 0755); err != nil {
60			return
61		}
62	
63		files, err := filepath.Glob(filepath.Join(w.WatchDir, "*.csv"))
64		if err != nil {
65			return
66		}
67	
68		for _, file := range files {
69			if err := w.importCSV(file); err != nil {
70				log.Printf("Error importing %s: %v", file, err)
71				// Move to error folder
72				errDir := filepath.Join(w.WatchDir, "errors")
73				os.MkdirAll(errDir, 0755)
74				os.Rename(file, filepath.Join(errDir, filepath.Base(file)))
75			} else {
76				// Move to processed folder
77				procDir := filepath.Join(w.WatchDir, "processed")
78				os.MkdirAll(procDir, 0755)
79				os.Rename(file, filepath.Join(procDir, filepath.Base(file)))
80				log.Printf("Successfully imported: %s", filepath.Base(file))
81			}
82		}
83	}
84	
85	func (w *CSVWatcher) importCSV(filePath string) error {
86		f, err := os.Open(filePath)
87		if err != nil {
88			return err
89		}
90		defer f.Close()
91	
92		reader := csv.NewReader(f)
93		records, err := reader.ReadAll()
94		if err != nil {
95			return err
96		}
97	
98		if len(records) < 2 {
99			return fmt.Errorf("CSV file has no data rows")
100		}
101	
102		headers := records[0]
103		headerMap := make(map[string]int)
104		for i, h := range headers {
105			headerMap[strings.ToLower(strings.TrimSpace(h))] = i
106		}
107	
108		baseName := strings.ToLower(filepath.Base(filePath))
109	
110		if strings.Contains(baseName, "enrollment") || strings.Contains(baseName, "student") {
111			return w.importEnrollment(records[1:], headerMap)
112		} else if strings.Contains(baseName, "org") || strings.Contains(baseName, "department") {
113			return w.importOrgStructure(records[1:], headerMap)
114		}
115	
116		return fmt.Errorf("unrecognized CSV type: %s", baseName)
117	}
