119	func (w *CSVWatcher) importEnrollment(rows [][]string, headers map[string]int) error {
120		for _, row := range rows {
121			username := getField(row, headers, "username")
122			fullName := getField(row, headers, "full_name")
123			email := getField(row, headers, "email")
124			role := getField(row, headers, "role")
125	
126			if username == "" || fullName == "" {
127				continue
128			}
129	
130			// Validate role against allowed values
131			validRoles := map[string]bool{
132				"student": true, "faculty": true, "clinician": true, "staff": true, "admin": true,
133			}
134			if role != "" && !validRoles[role] {
135				log.Printf("CSV import: skipping user %s — invalid role %q", username, role)
136				continue
137			}
138			if role == "" {
139				role = "student" // Default role
140			}
141	
142			// Derive org from CSV field or default to first org
143			orgName := getField(row, headers, "organization")
144			var orgID uint
145			if orgName != "" {
146				var org models.Organization
147				if err := w.DB.Where("name = ?", orgName).First(&org).Error; err == nil {
148					orgID = org.ID
149				}
150			}
151			if orgID == 0 {
152				var org models.Organization
153				w.DB.First(&org)
154				orgID = org.ID
155			}
156	
157			// Eligibility: CSV can include "eligible" field (true/false). Ineligible users are deactivated.
158			eligible := getField(row, headers, "eligible")
159			isEligible := eligible == "" || strings.EqualFold(eligible, "true") || eligible == "1"
160	
161			// Department sync from CSV
162			deptName := getField(row, headers, "department")
163			var deptID *uint
164			if deptName != "" {
165				var dept models.DepartmentRecord
166				if err := w.DB.Where("name = ? AND organization_id = ?", deptName, orgID).First(&dept).Error; err == nil {
167					deptID = &dept.ID
168				}
169			}
170	
171			var user models.User
172			err := w.DB.Where("username = ?", username).First(&user).Error
173			if err == gorm.ErrRecordNotFound {
174				user = models.User{
175					Username:       username,
176					PasswordHash:   "$2a$10$placeholder", // Needs admin password reset
177					FullName:       fullName,
178					Email:          email,
179					Role:           models.Role(role),
180					OrganizationID: orgID,
181					DepartmentID:   deptID,
182					Active:         isEligible,
183				}
184				w.DB.Create(&user)
185			} else if err == nil {
186				user.FullName = fullName
187				user.Email = email
188				user.Active = isEligible
189				if deptID != nil {
190					user.DepartmentID = deptID
191				}
192				w.DB.Save(&user)
193			}
194		}
195		return nil
196	}
