247	// IsInternalURL checks if a URL points to a private/internal network address only.
248	func IsInternalURL(rawURL string) bool {
249		parsed, err := neturl.Parse(rawURL)
250		if err != nil {
251			return false
252		}
253		host := parsed.Hostname()
254		// Allow loopback, .local, .internal, .corp, and RFC1918 patterns
255		if host == "localhost" || host == "127.0.0.1" || host == "::1" {
256			return true
257		}
258		if strings.HasSuffix(host, ".local") || strings.HasSuffix(host, ".internal") || strings.HasSuffix(host, ".corp") {
259			return true
260		}
261		// Check RFC1918 prefixes
262		for _, prefix := range []string{"10.", "192.168.", "172.16.", "172.17.", "172.18.", "172.19.",
263			"172.20.", "172.21.", "172.22.", "172.23.", "172.24.", "172.25.", "172.26.", "172.27.",
264			"172.28.", "172.29.", "172.30.", "172.31."} {
265			if strings.HasPrefix(host, prefix) {
266				return true
267			}
268		}
269		return false
270	}
