272	func (s *WebhookService) RegisterEndpointForOrg(rawURL, eventType, secret string, orgID uint) error {
273		if !IsInternalURL(rawURL) {
274			return fmt.Errorf("webhook URL must target an internal network address")
275		}
276		ep := &models.WebhookEndpoint{
277			OrganizationID: orgID,
278			URL:            rawURL,
279			EventType:      eventType,
280			Secret:         secret,
281			Active:         true,
282		}
283		return s.DB.Create(ep).Error
284	}
