565	
566	func MaskSSN(ssn string, role models.Role) string {
567		if ssn == "" {
568			return ""
569		}
570		if role == models.RoleAdmin {
571			return ssn
572		}
573		// Show only last 4 digits
574		clean := strings.ReplaceAll(strings.ReplaceAll(ssn, "-", ""), " ", "")
575		if len(clean) >= 4 {
576			return "***-**-" + clean[len(clean)-4:]
577		}
578		return "***-**-****"
579	}
580	
581	func MaskEmail(email string, role models.Role) string {
582		if role == models.RoleAdmin || role == models.RoleClinician {
583			return email
584		}
585		parts := strings.Split(email, "@")
586		if len(parts) != 2 {
587			return "***@***"
588		}
589		name := parts[0]
590		if len(name) > 2 {
591			name = name[:2] + "***"
592		}
593		return name + "@" + parts[1]
594	}
