27	// enforceScopeForHealth uses EnforceDeptScope for department-level users (clinicians/staff)
28	// and EnforceSelfScope for students/faculty. This ensures cross-department access is blocked.
29	func (h *HealthHandler) enforceScopeForHealth(c *gin.Context, targetUserID uint) bool {
