163	func (h *HealthHandler) RecordVitals(c *gin.Context) {
164		user := GetCurrentUser(c)
165		targetUserID, _ := strconv.ParseUint(c.PostForm("user_id"), 10, 64)
166	
167		// Enforce data scope — clinicians can only record vitals for patients in their department
168		if !h.enforceScopeForHealth(c, uint(targetUserID)) {
169			c.JSON(http.StatusForbidden, gin.H{"error": "access denied: cannot record vitals for this patient"})
170			return
171		}
172		_ = user
173	
174		weightLb, _ := strconv.ParseFloat(c.PostForm("weight_lb"), 64)
175		bpSys, _ := strconv.Atoi(c.PostForm("bp_systolic"))
176		bpDia, _ := strconv.Atoi(c.PostForm("bp_diastolic"))
177		tempF, _ := strconv.ParseFloat(c.PostForm("temperature_f"), 64)
178		hr, _ := strconv.Atoi(c.PostForm("heart_rate"))
179	
180		// Validate vitals ranges
181		var validationErrors []string
182		if weightLb != 0 && (weightLb < 1 || weightLb > 1000) {
183			validationErrors = append(validationErrors, "Weight must be between 1 and 1000 lb")
184		}
185		if bpSys != 0 && (bpSys < 40 || bpSys > 300) {
186			validationErrors = append(validationErrors, "Systolic BP must be between 40 and 300")
187		}
188		if bpDia != 0 && (bpDia < 20 || bpDia > 200) {
189			validationErrors = append(validationErrors, "Diastolic BP must be between 20 and 200")
190		}
191		if bpSys != 0 && bpDia != 0 && bpDia >= bpSys {
192			validationErrors = append(validationErrors, "Diastolic BP must be less than systolic BP")
193		}
194		if tempF != 0 && (tempF < 85 || tempF > 115) {
195			validationErrors = append(validationErrors, "Temperature must be between 85 and 115 °F")
196		}
197		if hr != 0 && (hr < 20 || hr > 300) {
198			validationErrors = append(validationErrors, "Heart rate must be between 20 and 300 bpm")
199		}
200		if len(validationErrors) > 0 {
201			c.HTML(http.StatusBadRequest, "error.html", gin.H{"error": "Validation errors: " + validationErrors[0]})
202			return
203		}
204	
205		vital := &models.Vital{
206			UserID:       uint(targetUserID),
207			WeightLb:     weightLb,
208			BPSystolic:   bpSys,
209			BPDiastolic:  bpDia,
210			TemperatureF: tempF,
211			HeartRate:    hr,
212			RecordedBy:   user.ID,
213		}
214	
215		vitalsReason := strings.TrimSpace(c.PostForm("reason"))
216		if vitalsReason == "" {
217			c.HTML(http.StatusBadRequest, "error.html", gin.H{"error": "reason is required for vitals recording"})
218			return
219		}
220	
221		if err := h.HealthSvc.RecordVitals(vital, vitalsReason); err != nil {
222			c.HTML(http.StatusInternalServerError, "error.html", gin.H{"error": err.Error()})
223			return
224		}
225	
226		c.Redirect(http.StatusFound, "/dashboard?user_id="+strconv.FormatUint(targetUserID, 10))
227	}
