351	func (h *HealthHandler) ClinicianPage(c *gin.Context) {
352		user := GetCurrentUser(c)
353		requestedDept := models.Department(c.DefaultQuery("dept", "general"))
354	
355		// Admins can view any department. Clinicians/staff can only view their own.
356		dept := requestedDept
357		if user.Role != models.RoleAdmin {
358			if user.DepartmentID == nil {
359				c.JSON(http.StatusForbidden, gin.H{"error": "no department assigned — contact admin"})
360				return
361			}
362			// Look up the user's department record to get the department name
363			var deptRec models.DepartmentRecord
364			if err := h.HealthSvc.DB.First(&deptRec, *user.DepartmentID).Error; err != nil {
365				c.JSON(http.StatusForbidden, gin.H{"error": "department not found"})
366				return
367			}
368			// Map department record name to Department enum
369			deptMap := map[string]models.Department{
370				"General Medicine": models.DeptGeneral,
371				"Laboratory":      models.DeptLab,
372				"Pharmacy":        models.DeptPharmacy,
373				"Nursing":         models.DeptNursing,
374			}
375			if mapped, ok := deptMap[deptRec.Name]; ok {
376				dept = mapped
377			} else {
378				dept = models.DeptGeneral
379			}
380			// Reject if clinician tries to view a different department
381			if requestedDept != dept && c.Query("dept") != "" {
382				c.JSON(http.StatusForbidden, gin.H{"error": "access denied: you can only view your own department"})
383				return
384			}
385		}
386	
387		orgID, _ := c.Get("orgID")
388		encounters, _ := h.HealthSvc.GetEncountersByDept(dept, orgID.(uint))
389	
