198	func (w *CSVWatcher) importOrgStructure(rows [][]string, headers map[string]int) error {
199		for _, row := range rows {
200			deptName := getField(row, headers, "department")
201			orgName := getField(row, headers, "organization")
202	
203			if deptName == "" {
204				continue
205			}
206	
207			var org models.Organization
208			if orgName != "" {
209				w.DB.Where("name = ?", orgName).FirstOrCreate(&org, models.Organization{Name: orgName})
210			} else {
211				w.DB.First(&org)
212			}
213	
214			var dept models.DepartmentRecord
215			w.DB.Where("name = ? AND organization_id = ?", deptName, org.ID).
216				FirstOrCreate(&dept, models.DepartmentRecord{Name: deptName, OrganizationID: org.ID})
217		}
218		return nil
219	}
