286	// DispatchForOrg sends webhook events scoped to a specific organization.
287	// orgID is required and must be > 0 to enforce tenant isolation.
288	func (s *WebhookService) DispatchForOrg(eventType string, payload interface{}, orgID uint) {
289		if orgID == 0 {
290			log.Printf("WARNING: DispatchForOrg called with orgID=0, skipping broadcast to prevent cross-tenant leak")
291			return
292		}
293		var endpoints []models.WebhookEndpoint
294		s.DB.Where("event_type = ? AND active = true AND organization_id = ?", eventType, orgID).Find(&endpoints)
295	
296		data, _ := json.Marshal(payload)
297	
298		for _, ep := range endpoints {
299			go s.deliver(ep, data)
300		}
301	}
302	
303	func (s *WebhookService) deliver(endpoint models.WebhookEndpoint, payload []byte) {
304		// Delivery-time revalidation: ensure target is still internal
305		if !IsInternalURL(endpoint.URL) {
306			s.logDelivery(endpoint.ID, string(payload), 0, "delivery blocked: non-internal URL", 1)
307			return
308		}
309		// Sign the payload once (payload bytes are immutable)
310		mac := hmac.New(sha256.New, []byte(endpoint.Secret))
311		mac.Write(payload)
312		signature := hex.EncodeToString(mac.Sum(nil))
313	
314		maxRetries := 3
315		for attempt := 1; attempt <= maxRetries; attempt++ {
316			// Create a FRESH request with a new body reader on every attempt
317			req, err := http.NewRequest("POST", endpoint.URL, bytes.NewReader(payload))
318			if err != nil {
319				s.logDelivery(endpoint.ID, string(payload), 0, err.Error(), attempt)
320				return
321			}
322			req.Header.Set("Content-Type", "application/json")
323			req.Header.Set("X-Webhook-Signature", signature)
324			req.Header.Set("X-Webhook-Event", endpoint.EventType)
325	
326			resp, err := s.client.Do(req)
327			if err != nil {
328				if attempt == maxRetries {
329					s.logDelivery(endpoint.ID, string(payload), 0, err.Error(), attempt)
330				}
331				time.Sleep(time.Duration(attempt) * time.Second)
332				continue
333			}
334			resp.Body.Close()
335			s.logDelivery(endpoint.ID, string(payload), resp.StatusCode, "", attempt)
336			return
337		}
338	}
