384	func (s *ReportingService) RefreshMaterializedViews() {
385		views := []string{"mv_clinic_utilization", "mv_booking_fill_rates", "mv_menu_sell_through"}
386		for _, v := range views {
387			start := time.Now()
388			// Try CONCURRENTLY first (requires unique index); fall back to blocking refresh
389			result := s.DB.Exec(fmt.Sprintf("REFRESH MATERIALIZED VIEW CONCURRENTLY %s", v))
390			if result.Error != nil {
391				s.DB.Exec(fmt.Sprintf("REFRESH MATERIALIZED VIEW %s", v))
392			}
