424	func (s *ReportingService) orgQuery(cacheKey, query string, orgID uint) ([]map[string]interface{}, error) {
425		s.mu.RLock()
426		if entry, ok := s.cache[cacheKey]; ok && time.Now().Before(entry.expiresAt) {
427			s.mu.RUnlock()
428			return entry.data.([]map[string]interface{}), nil
429		}
430		s.mu.RUnlock()
431	
432		var results []map[string]interface{}
433		rows, err := s.DB.Raw(query, orgID).Rows()
434		if err != nil {
435			return nil, err
436		}
437		defer rows.Close()
438		cols, _ := rows.Columns()
439		for rows.Next() {
440			row := make(map[string]interface{})
441			vals := make([]interface{}, len(cols))
442			valPtrs := make([]interface{}, len(cols))
443			for i := range vals {
444				valPtrs[i] = &vals[i]
445			}
446			rows.Scan(valPtrs...)
447			for i, col := range cols {
448				row[col] = vals[i]
449			}
450			results = append(results, row)
451		}
452	
453		s.mu.Lock()
454		s.cache[cacheKey] = &cacheEntry{data: results, expiresAt: time.Now().Add(s.cacheTTL)}
455		s.mu.Unlock()
456		return results, nil
457	}
