528	func (s *ReportingService) executeReportJob(jobID uint) {
529		var job models.ReportJob
530		if err := s.DB.First(&job, jobID).Error; err != nil {
531			return
532		}
533		s.DB.Model(&job).Update("status", "running")
534	
535		var data []map[string]interface{}
536		var err error
537		switch job.ReportType {
538		case "clinic_utilization":
539			data, err = s.GetClinicUtilization(job.OrganizationID)
540		case "booking_fill_rates":
541			data, err = s.GetBookingFillRates(job.OrganizationID)
542		case "menu_sell_through":
543			data, err = s.GetMenuSellThrough(job.OrganizationID)
544		default:
545			err = fmt.Errorf("unknown report type: %s", job.ReportType)
546		}
547	
548		now := time.Now()
549		if err != nil {
550			s.DB.Model(&job).Updates(map[string]interface{}{"status": "failed", "result": err.Error(), "completed_at": now})
551			return
552		}
553		jsonData, _ := json.Marshal(data)
