											<input type="hidden" name="status" value="confirmed"/>
											if d.IsAdmin {
												<input type="hidden" name="note" value="Confirmed by admin"/>
											} else {
												<input type="text" name="note" placeholder="Reason..." class="inline-note" value="Confirmed"/>
											}
											<button type="submit" class="btn btn-sm btn-success">Confirm</button>
										</form>
									}
									if b.Status == "initiated" || b.Status == "confirmed" {
										<form method="POST" action={ templ.SafeURL(fmt.Sprintf("/bookings/%d/transition", b.ID)) } style="display:inline;">
											<input type="hidden" name="status" value="canceled"/>
											if d.IsAdmin {
												<input type="hidden" name="note" value="Canceled by admin"/>
											} else {
												<input type="text" name="note" placeholder="Reason for cancellation..." class="inline-note" required/>
											}
											<button type="submit" class="btn btn-sm btn-danger">Cancel</button>
										</form>
