											<input type="hidden" name="status" value="refunded"/>
											<input type="text" name="note" placeholder="Refund reason..." class="inline-note" value="Refund requested"/>
											<button type="submit" class="btn btn-sm btn-outline">Refund</button>
										</form>
									}
									<button class="btn btn-sm btn-outline" onclick={ templ.ComponentScript{Call: fmt.Sprintf("showBookingAudit(%d)", b.ID)} }>Audit</button>
								</td>
							</tr>
						}
					</tbody>
				</table>
			} else {
				<p class="text-muted">No bookings yet.</p>
			}
		</div>
	</div>

	if !d.IsAdmin {
		<!-- Audit Modal -->
		<div id="auditModal" class="modal" style="display:none;">
			<div class="modal-content">
				<div class="modal-header">
					<h3>Booking Audit Trail</h3>
					<button onclick="closeModal('auditModal')" class="btn-close">&times;</button>
				</div>
				<div id="auditContent" class="modal-body"></div>
			</div>
		</div>
	}
}

func venueCapacity(cap int) string {
	if cap > 0 {
		return fmt.Sprintf(", cap: %d", cap)
	}
	return ""
}

templ BookingsPage(d BookingsData) {
	if d.IsAdmin {
		@Layout("All Training Sessions", d.User, BookingsContent(d))
	} else {
		@Layout("Training Sessions", d.User, BookingsContent(d))
	}
}
"}

